mapper.select:
SELECT t.* FROM pptask t WHERE IFNULL(t.total_number, 0) > IFNULL(t.compated_number, 0) + ( SELECT COUNT(*) FROM pptask_claim c WHERE c.task_id = t.id AND c.status = 'CLAIMED' AND c.lease_expire_time > NOW() ) AND NOT EXISTS ( SELECT 1 FROM pptask_claim c2 WHERE c2.task_id = t.id AND c2.device_id = #{deviceId} )
AND t.room_id = #{roomId}
ORDER BY t.id ASC LIMIT 1 FOR UPDATE
